import subprocess
result = subprocess.run(['hermes', 'config', 'edit'], capture_output=True, text=True, timeout=10)
# Just show the gateway section
import os
config_path = os.path.expanduser('~/.hermes/config.yaml')
if os.path.exists(config_path):
    with open(config_path) as f:
        content = f.read()
    # Find gateway section
    if 'gateway' in content:
        lines = content.split('\n')
        in_gateway = False
        gateway_lines = []
        for line in lines:
            if 'gateway:' in line:
                in_gateway = True
            if in_gateway:
                gateway_lines.append(line)
                if line.strip() and not line.startswith(' ') and not line.startswith('\t') and 'gateway:' not in line:
                    break
        print('\n'.join(gateway_lines[:50]))
    else:
        print("No gateway section found")
else:
    print("Config file not found")
